var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"휴우, 일단 따돌린 것 같네요.","JPN":"ふぅ、一旦はまいたようですね。","ENG":"Whew, we ditched them for now.","TWN":"呼，算是把他們甩掉了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 군사기지를 벗어나지 못하는 한, 결국 잡히겠지만요.","JPN":"この軍事基地から離れない限り、どのみち捕まるのでしょうけど。","ENG":"But we'll get caught unless we get out of this military base.","TWN":"但只要沒逃出這個軍事基地，終究還是會被抓住的。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 일단은 숨 좀 돌리기로 해요.","JPN":"ハハ、とりあえず一息つきましょうか。","ENG":"Hah hah. Let's take a breather for now.","TWN":"哈哈，先喘口氣吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"다이브하자마자 싸웠더니 제 속이 다 울렁거리네요.","JPN":"ダイブ直後に戦ったせいで、胸がムカムカします。","ENG":"My stomach is churning from having to fight right after we dived.","TWN":"竟然剛躍入就要打架，我的心臟都在砰砰跳呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......할 수 없죠. 저기 저 방으로 들어가요.","JPN":"……仕方ありませんね。向こうの部屋に入りましょう。","ENG":"Okay, let's enter that room over there.","TWN":"……沒辦法。去那邊的房間吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이런 상황에서 단둘만의 시츄에이션으로 유인하다니, 대담하시네요.","JPN":"こんな状況で二人っきりになろうだなんて、大胆ですね。","ENG":"You want to be alone with me in a situation like this? You're pretty bold.","TWN":"在這種情況下，居然還要製造兩人獨處的機會，妳真是大膽呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시끄러워요, 이 외설가!","JPN":"ちょっと黙ってください、このお調子者！","ENG":"Get your mind out of the gutter!","TWN":"吵死了，妳這變態！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런데 여긴 대체 어디일까요?","JPN":"ところで、ここはいったいどこでしょうね？","ENG":"By the way, where on earth are we?","TWN":"不過，這裡到底是哪裡呢？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자살에 가까운 고심도 다이브라고 해서 뭐가 나오든 놀라지 않으려고 했는데......","JPN":"命の保障がないほどの高深度ダイブということで、何が出現しても驚くまいと覚悟していたのですが……","ENG":"Since this high-depth Dive was all but suicidal, I readied myself for all possibilities.","TWN":"聽說是接近自殺的深度躍入，我想說無論出現什麼，我都不會被嚇到……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이면세계에 이런 곳이 있다는 이야기는 들은 적이 없네요.","JPN":"裏世界にこんな場所があるとは、聞いたことがありません。","ENG":"But I've never heard of a place like this in the Counterside.","TWN":"但我可從沒聽說過異界還有這種地方。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여긴 이면세계라기보단 멀쩡한 현실 세계잖아요?","JPN":"ここは裏世界というより、普通の現実世界じゃないですか？","ENG":"It looks more like it's in the Normalside than in the Counterside.","TWN":"這裡比起異界，更像正常的現實世界不是嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"설마 저희들, 그냥 장소만 이동한 건 아니겠죠?","JPN":"まさか私たち、ただ移動しただけなのでは？","ENG":"We didn't just move to a different place, did we?","TWN":"我們不會只是移動到了別的場所吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아뇨. 이런 시설은 우리 세계에 존재하지 않습니다.","JPN":"いいえ、こんな施設は私たちの世界には存在しません。","ENG":"No. Facilities like this don't exist in our world.","TWN":"不會。這種設施不存在於我們的世界。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"만일 있었다면 델타 세븐 정보과 소속인 제가 몰랐을 리 없어요.","JPN":"もし存在するなら、デルタセブン監査課所属の私が知らないわけありませんから。","ENG":"If it did, I would have known. I'm in Delta Seven's Intelligence Department.","TWN":"如果存在的話，身為第七三角洲部隊情報部的所屬人員，我不可能不知道。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 그렇게 확신할 수 있는 근거는요?","JPN":"ふーん、そう確信する根拠は？","ENG":"Hm, what makes you so sure?","TWN":"嗯，妳這麼確信的根據呢？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당연히 있죠. 여기, 계측기를 보세요.","JPN":"もちろんあります。計測器の……\\nここを見てください。","ENG":"Here, take a look at this meter.","TWN":"當然有。請看這個儀器。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 세계의 물질 구성 원소는 우리 몸을 이루는 것보다 양자 위상이 5단계 이상 차이나요.","JPN":"この世界の物質を構成する元素は、私たちの身体と比べて、量子位相が5段階以上離れているのです。","ENG":"Elements in this world are at a quantum phase that's at least 5 levels higher than those of our bodies.","TWN":"這個世界的物質構成元素與我們的身體相比，量子能量相差5級以上。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};